'use client'
import { cn } from '@cascivo/core'
import type { HTMLAttributes } from 'react'
import styles from './segmented-control.module.css'

export interface SegmentedControlOption {
  label: string
  value: string
  disabled?: boolean
}

export interface SegmentedControlProps extends Omit<HTMLAttributes<HTMLDivElement>, 'onChange'> {
  options: SegmentedControlOption[]
  value: string
  onValueChange: (v: string) => void
  size?: 'sm' | 'md' | 'lg'
  disabled?: boolean
}

export function SegmentedControl({
  options,
  value,
  onValueChange,
  size = 'md',
  disabled = false,
  className,
  ...props
}: SegmentedControlProps) {
  function handleKeyDown(e: React.KeyboardEvent<HTMLButtonElement>, index: number) {
    const enabledOptions = options.filter((o) => !o.disabled)
    const currentEnabled = enabledOptions.findIndex((o) => o.value === options[index]?.value)
    if (e.key === 'ArrowRight') {
      e.preventDefault()
      const next = enabledOptions[(currentEnabled + 1) % enabledOptions.length]
      if (next) onValueChange(next.value)
    } else if (e.key === 'ArrowLeft') {
      e.preventDefault()
      const prev =
        enabledOptions[(currentEnabled - 1 + enabledOptions.length) % enabledOptions.length]
      if (prev) onValueChange(prev.value)
    }
  }

  return (
    <div
      role="group"
      className={cn(styles['wrapper'], className)}
      data-size={size}
      data-disabled={disabled ? '' : undefined}
      {...props}
    >
      {options.map((opt, i) => (
        <button
          key={opt.value}
          type="button"
          role="radio"
          aria-checked={opt.value === value}
          data-selected={opt.value === value ? '' : undefined}
          data-size={size}
          className={styles['segment']}
          disabled={disabled || opt.disabled}
          onClick={() => {
            if (!opt.disabled) onValueChange(opt.value)
          }}
          onKeyDown={(e) => handleKeyDown(e, i)}
        >
          {opt.label}
        </button>
      ))}
    </div>
  )
}

@layer cascivo.component {
  .wrapper {
    display: inline-flex;
    gap: var(--cascivo-space-1);
    padding: var(--cascivo-space-1);
    background-color: var(--cascivo-color-bg-subtle);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);

    &[data-size='sm'] {
      --_seg-h: 1.75rem;
      --_seg-font: var(--cascivo-text-xs);
      --_seg-px: var(--cascivo-space-2);
    }

    &[data-size='md'] {
      --_seg-h: 2.25rem;
      --_seg-font: var(--cascivo-text-sm);
      --_seg-px: var(--cascivo-space-3);
    }

    &[data-size='lg'] {
      --_seg-h: 2.75rem;
      --_seg-font: var(--cascivo-text-base);
      --_seg-px: var(--cascivo-space-4);
    }

    &[data-disabled] {
      opacity: 0.5;
    }
  }

  .segment {
    height: var(--_seg-h, 2.25rem);
    padding-inline: var(--_seg-px, var(--cascivo-space-3));
    font-family: var(--cascivo-font-sans);
    font-size: var(--_seg-font, var(--cascivo-text-sm));
    font-weight: var(--cascivo-font-medium);
    color: var(--cascivo-color-text-subtle);
    background: none;
    border: none;
    border-radius: var(--cascivo-radius-item);
    cursor: pointer;
    transition:
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out),
      color var(--cascivo-duration-150) var(--cascivo-ease-out);
    white-space: nowrap;

    &:hover:not(:disabled):not([data-selected]) {
      color: var(--cascivo-color-text);
      background-color: rgb(from var(--cascivo-color-text) r g b / 0.05);
    }

    &:focus-visible {
      outline: 2px solid var(--cascivo-color-accent);
      outline-offset: 1px;
    }

    &[data-selected] {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-surface);
      box-shadow: var(--cascivo-shadow-sm);
    }

    &:disabled {
      cursor: not-allowed;
      opacity: 0.5;
    }
  }
}
